"""
MKT Original Commentary — Daniel chapters 1–2
Run: python3 scripts/zc-original-daniel-1-2-fill.py

Source data used:
- data/interlinear/daniel.json
- data/translation/draft/mediating/daniel.json (MKT text)
- data/translation/glossary-hebrew.json (semantic ranges)

Key decisions in this range:
- Ch 1 is Hebrew; ch 2:4b–7:28 is Biblical Aramaic. The switch is noted at 2:4.
- Daniel avoids the covenant name YHWH; uses Elohim/Elah and Adonai instead —
  deliberate pattern reflecting exile context; noted at 1:2.
- 'raz' (mystery) is a Persian loanword appearing first at 2:18; carry this term forward.
- 'pathbag' (king's food, 1:5) is a Persian loanword; not ordinary diet but covenantal
  boundary marker with likely cultic dimension.
- The statue (tselem, 2:31) uses the same root as Gen 1:26-27 — the human image of God
  now recast as imperial idol. This is noted but not over-read.
- 'segid' (to bow/worship, 2:46) is the same Aramaic term used for idol worship in ch 3.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

DANIEL = {
  "1": {
    "1": '<p><strong>Third year of Jehoiakim</strong> — the dating creates a surface tension with Jer 25:1, which places Nebuchadnezzar\'s first western campaign in Jehoiakim\'s fourth year. The resolution lies in counting systems: Daniel follows Babylonian accession-year reckoning (the coronation year counts as year 0, so "year 1" begins at the first New Year after accession), while Jeremiah uses Judean non-accession reckoning (the coronation year itself is "year 1"). The two systems yield the same regnal year labelled differently by one integer. <em>Nebukadretssar</em> (H5019) is a Hebrew approximation of Akkadian <em>Nabû-kudurri-uṣur</em> ("Nebo protect the boundary-stone").</p>',
    "2": '<p><strong>The Lord gave</strong> (<em>Adonai</em>, H136) — Daniel\'s narrator uses <em>Adonai</em> here rather than the covenant name YHWH. Daniel avoids YHWH throughout, reflecting the theological reticence of exile: the covenant Name belongs to the Land and Temple cult; in Babylon, the more universal titles Adonai and Elohim predominate. <em>Elohim</em> (H430) refers to both the temple of Israel\'s God and the house of "his god" (Marduk) in the same verse — a deliberate irony. <strong>Treasuries</strong> (<em>otsar</em>, H214) — the temple vessels ending in Babylon\'s treasury foreshadow the central crisis of ch 5.</p>',
    "3": '<p><strong>Seed</strong> (<em>zera</em>, H2233) — a covenantal term normally used for offspring of the promise (Abraham, David, the holy seed). These young men are the covenant seed of Israel being absorbed into empire. <em>Saris</em> (H5631) may mean "eunuch" (literal) or simply "court official" (extended); the context suggests both roles existed, with the intent being social as well as physical reorientation.</p>',
    "4": '<p><strong>Wisdom vocabulary triad:</strong> <em>chokmah</em> (H2451, practical wisdom), <em>da\'at</em> (H1847, knowledge/relational knowing), and <em>bin</em> (H995, discernment/understanding) — the three epistemic terms of Proverbs\' instruction. Babylon is consciously recruiting Israel\'s covenant-wisdom tradition for its own service. <strong>Ability</strong> (<em>koach</em>, H3581) implies physical and intellectual strength; these are Israel\'s finest, selected to represent the empire\'s cosmopolitan competence.</p>',
    "5": '<p><strong>Daily portion</strong> (<em>pathbag</em>, H6598) — a Persian loanword, appearing only in Daniel and Esther in the Hebrew Bible, meaning the royal allotment of food and wine. The issue Daniel refuses is not merely dietary hygiene but covenantal boundary: food from the king\'s table was likely offered to Babylonian deities, making consumption an act of participation in Babylonian cult. <em>Gadel</em> (H1431, to rear/nourish) uses the same root as "great" — Babylon\'s program of greatness-formation is enacted through food. <strong>Three years</strong> — H7969 shaloshet; a fixed apprenticeship period, after which imperial service begins.</p>',
    "6": '<p>Four Hebrew theophoric names: <strong>Daniel</strong> (H1840, "El is my judge"), <strong>Hananiah</strong> (H2608, "YHWH has been gracious"), <strong>Mishael</strong> (H4332, "who is what El is?"), <strong>Azariah</strong> (H5838, "YHWH has helped"). All four embed Israel\'s covenant God; all four will be renamed. The tribe of Judah (H3063) is the messianic tribe — this detail is theologically loaded given later Davidic echoes.</p>',
    "7": '<p><strong>Name replacement</strong> — the Babylonian names (Belteshazzar, Shadrach, Meshach, Abednego) embed Babylonian deity names (Bel, Aku/Marduk). The renaming is an act of identity colonization: to rename is to reclaim ownership, erasing the theophoric Hebrew names and their testimony to YHWH. The four men will demonstrate throughout the book that names do not determine identity.</p>',
    "8": '<p><strong>Defile</strong> (<em>ga\'al</em>, H1351) — to contaminate, make ritually impure. The same root underlies <em>go\'el</em> (kinsman-redeemer) by ironic contrast: Daniel refuses what cannot be redeemed. <strong>Set upon his heart</strong> (<em>sam al-libbo</em>) — the <em>lev</em> (H3820) in Hebrew is the seat of decision and will, not merely sentiment. Daniel\'s act is a covenantal act of will, not just conscientious scruple. <strong>Sought permission</strong> (<em>vayevaqesh</em>, H1245) — the deliberate, courteous approach models how covenant faithfulness is exercised within empire: not provocative refusal but principled request.</p>',
    "9": '<p><strong>Favour and compassion</strong> — <em>chesed</em> (H2617) and <em>rachamim</em> (H7356): the two great covenant-mercy terms appear together. God\'s response to Daniel\'s faithful resolve is not passive; God actively works within the bureaucratic structure of the empire to open the way. This pairing recurs in covenantal contexts throughout the OT (Exod 34:6; Hos 2:19).</p>',
    "10": '<p><strong>Appearance</strong> (<em>mar\'eh</em>, H4758) — physical countenance as visible evidence of inner state. The official\'s concern is practical: visible malnourishment would reflect badly on the palace and endanger him. <em>Na\'ar</em> (H5288) = young man; the diminutive framing underlines their vulnerability within the imperial system.</p>',
    "11": '<p>The <em>meltsar</em> (H4453) — often translated "steward" or "overseer"; the term may be a loanword for a specific court functionary. Daniel goes to the more proximate official rather than forcing the issue with Ashpenaz, a pragmatic but also courteous strategy.</p>',
    "12": '<p><strong>Vegetables</strong> (<em>zeroa\'im</em>, H2235, lit. "things sown" or "seed-vegetables") — the word emphasizes plant-produce as opposed to meat. <strong>Water only</strong> (<em>mayim</em>, H4325) — the contrast with the wine of the king\'s table is sharp. The proposal is not asceticism but a practical boundary marker.</p>',
    "13": '<p><strong>Compare</strong> (<em>u\'re\'eh</em>, from H7200 ra\'ah) — "and you will see"; an empirical test of whether faithfulness to covenant norms produces flourishing. The book consistently appeals to visible, verifiable outcomes as evidence of divine blessing.</p>',
    "14": '<p><strong>He agreed</strong> (<em>vayishma\'</em>, from H8085 shama) — literally "he heard them." The same term used for obedience to God\'s voice is used here for the official\'s response to Daniel\'s request; hearing and heeding are both <em>shama</em>. The ten-day test period mirrors the ten plagues and other ten-day/ten-unit testing patterns in the OT.</p>',
    "15": '<p><strong>Healthier and better nourished</strong> — <em>bari</em> (H1277, fat/robust) and <em>besar</em> (H1320, flesh); the physical evidence of covenantal blessing is unmistakable. "Better nourished" than those eating the royal menu subverts the implicit claim that imperial provision is the path to human flourishing.</p>',
    "16": '<p>The steward simply acts on what he observed: <em>nasa\'</em> (H5375) their food and gave (<em>natan</em>, H5414) vegetables. The matter is resolved quietly and practically — no confrontation, no decree, just the empirical outcome vindicating Daniel\'s request.</p>',
    "17": '<p><strong>Knowledge and wisdom given by God</strong> — the triad of ch 1:4 (chokmah, da\'at, bin) is now attributed explicitly to divine gift, not Babylonian education. <strong>Chazon</strong> (H2377) and <strong>chalom</strong> (H2472) are distinguished: <em>chazon</em> is prophetic/visionary revelation (the major prophetic genre), while <em>chalom</em> is the ordinary dream vehicle. Daniel receives both. This verse is the theological hinge: whatever Babylon trained them in, God is the source of their extraordinary competence.</p>',
    "18": '<p>The <em>miqetz</em> (H7093, at the end of) — a typical Hebrew temporal formula marking the fulfillment of the appointed period. <em>Hevisham</em> (from H935, brought/presented) — the official presents them to Nebuchadnezzar for examination.</p>',
    "19": '<p><strong>Stood before the king</strong> (<em>vaya\'amdu lifnei ha-melek</em>, H5975) — to "stand before" a king is the technical phrase for entering royal service. None were found equal (<em>nimtsa\'</em>, H4672) — "to be found" is a legal/evaluative term; the four are the standard against which all others are measured.</p>',
    "20": '<p><strong>Ten times</strong> (<em>eser yadot</em>) — hyperbolic superiority formula. <em>Chartomim</em> (H2748, magicians) and <em>ashshaphim</em> (H826, enchanters/astrologers) — the same two categories Pharaoh summons in Exod 7:11; the echo is not accidental. Daniel and his companions surpass Babylon\'s wise men as decisively as Moses surpassed Egypt\'s.</p>',
    "21": '<p><strong>Daniel remained until the first year of Cyrus</strong> — a chronological bracket closing ch 1. The first year of Cyrus (H3566) = 539 BCE, when the Persians conquered Babylon and Cyrus issued his famous decree permitting exiles to return. Daniel\'s survival across the entire exile period — from the Babylonian conquest of Jerusalem to the Persian restoration — is itself a covenant-faithfulness witness.</p>'
  },
  "2": {
    "1": '<p><strong>Second year of Nebuchadnezzar</strong> — this appears to conflict with the three-year training in ch 1, but the Babylonian accession-year system again resolves it: the "second year" from Nebuchadnezzar\'s accession falls within the training period if it began after the initial capture. <em>Ruach</em> (H7307) = spirit/breath; Nebuchadnezzar\'s <em>ruach</em> was agitated — the same term used for the Spirit of God moving over the waters (Gen 1:2). <em>Shena</em> (H8142, sleep) fled from him; divine unrest preparing for revelation.</p>',
    "2": '<p>Four categories of Babylonian specialists summoned: <em>chartomim</em> (H2748, magicians), <em>ashshaphim</em> (H826, enchanters), <em>mekashephim</em> (H3784, sorcerers), and <em>kasdim</em> (H3778, Chaldeans — here a professional class of diviners, not merely an ethnic designation). This fourfold list mirrors Exod 7:11 (Pharaoh\'s magicians), placing Nebuchadnezzar\'s wisdom establishment in the typological line of every empire that opposes the purposes of the God of Israel.</p>',
    "3": '<p><em>Saam</em> (H5590) — his spirit was troubled; the same root appears in Gen 41:8 when Pharaoh\'s spirit was troubled after his dream. The structural parallel with Joseph is deliberate: a Hebrew in a foreign court, given understanding of a king\'s dream, rises to power. Daniel surpasses Joseph as the pattern escalates.</p>',
    "4": '<p><strong>In Aramaic</strong> (<em>Aramit</em>, H762) — the book\'s language shifts here from Hebrew to Biblical Aramaic and does not return to Hebrew until 8:1. Aramaic was the lingua franca of the ancient Near East from the 8th century BCE; the shift signals the international scope of what follows — the Aramaic section (2:4b–7:28) addresses the nations as such. <em>Chelem</em> (Aramaic H2493, dream) replaces the Hebrew <em>chalom</em>. <em>Peshar</em> (H6591, interpretation) — this Aramaic term becomes the technical vocabulary of apocalyptic disclosure.</p>',
    "5": '<p><strong>The matter is gone from me</strong> (<em>milleta min-ni azdat</em>) — <em>azda</em> (H230) means certain/decreed; the king\'s decree is fixed. If they cannot provide both dream and interpretation, the consequence is death and the destruction of their houses. The impossible demand reveals that the Babylonian wise men\'s entire system depends on the king supplying the dream — they can interpret but not reveal. Only God can do both.</p>',
    "6": '<p><em>Peshar</em> recurs; the conditional promise of gifts and honour (<em>yeqar</em>, H3367, honour/dignity; <em>segu</em>, H7690, abundant gifts) frames the test as both threat and reward. The term <em>yeqar</em> will reappear in Nebuchadnezzar\'s ultimate doxology (v.37).</p>',
    "7": '<p>The wise men repeat their request for the dream (<em>chelem</em>) first, then interpretation (<em>peshar</em>) — they need the raw material before they can function. Their system is one of interpretive pattern-matching applied to known data; revelation of the unknown is beyond them.</p>',
    "8": '<p><em>Yatzib</em> (H3330, certain/fixed) — the king perceived they were buying time (<em>zaban</em>, H2118, to gain time). The confrontation exposes the fundamental limitation of human wisdom: it can manage what is already known but cannot access the divine council.</p>',
    "9": '<p>The king\'s accusation is essentially correct: without the ability to tell the dream, any interpretation could be fabricated. The demand for the dream itself is a kind of epistemological test — only genuine access to the divine could produce it.</p>',
    "10": '<p><strong>There is not a man on earth</strong> — <em>enash</em> (H606, Aramaic for "man/person") — the universal negative claim of the wise men is theologically correct even if they do not intend it that way: no human being has access to the king\'s dream. Only "the gods whose dwelling is not with flesh" (<em>beshar</em>, H1321) — they inadvertently articulate the gap that only Daniel\'s God can bridge.</p>',
    "11": '<p><strong>A rare thing</strong> (<em>yaqqir</em>, H3358) — difficult/precious/rare. The gods do not dwell with flesh (<em>beshar</em>): the Babylonian theologians acknowledge that divine-human communication is exceptional. Daniel\'s God closes this gap precisely because he is the God who reveals mysteries — the same God who became flesh (John 1:14) will later be described as one who "dwells with" his people (Rev 21:3).</p>',
    "12": '<p>The decree to destroy all wise men of Babylon would include Daniel and his companions — they are caught in the crisis they did not cause. <em>Beaz</em> (H1149, in anger) — Nebuchadnezzar\'s rage is the context for Daniel\'s intervention.</p>',
    "13": '<p>Daniel and his companions were sought (<em>mitbaqqurin</em>, from H1156, to seek) for execution. The situation is urgent. The verb is the same as <em>be\'a</em> (to pray/petition) in v.18 — the seeking that threatens their lives will be matched by the seeking that saves them.</p>',
    "14": '<p>Daniel speaks with <em>ta\'em u-ve\'em</em> (H2942, prudence and discretion) — <em>ta\'em</em> is often used for discernment/judgment; Daniel does not panic but responds with the wisdom God has already given him (1:17). He asks for time — <em>zeman</em> (H2166, appointed time) — the same term used for the eschatological "time" throughout Daniel.</p>',
    "15": '<p>The question "why is the decree so urgent?" (<em>me-di milleta machtsepah min-qadam malka</em>) — <em>machtsepah</em> (H2685, urgent/pressing). Daniel seeks information before acting — the wisdom response to crisis is to understand before reacting.</p>',
    "16": '<p><em>U-ve\'ah</em> (H1156, petitioned/requested) — Daniel requests time from the king, and the king grants it (<em>shim</em>, H7761, appointed/set). This brief verse is structurally important: Daniel does not pray first then act; he takes the practical step with the king first, then brings his companions into prayer. Wisdom and prayer are integrated, not sequential alternatives.</p>',
    "17": '<p><em>Chavrayhi</em> (H2269, companions/friends) — Hananiah, Mishael, and Azariah are Daniel\'s covenant community within exile. He does not face the crisis alone; the corporate nature of the response reflects the communal character of prayer in Israel.</p>',
    "18": '<p><strong>Seek mercy</strong> (<em>le-mevey rachamim</em>) — <em>rachamim</em> (H7356) again (cf. 1:9); God\'s tender mercy is the constant resource. <strong>Mystery</strong> (<em>raz</em>, H7328) — a Persian loanword meaning "secret" or "hidden thing," here entering Daniel\'s theological vocabulary for the first time. <em>Raz</em> will appear nine times in Daniel (chs. 2 and 4), always for the divine secret that only God can disclose. The NT inherits this vocabulary: Paul\'s <em>mystērion</em> (mystery of Christ, Eph 3:3-4) is the Greek equivalent of <em>raz</em>.</p>',
    "19": '<p><strong>Night vision</strong> (<em>chezu leilya</em>) — <em>chezu</em> (H2376, Aramaic for vision) + <em>leilya</em> (H3916, at night). The <em>raz</em> was revealed (<em>gali</em>, H1541, to reveal/uncover) to Daniel — the same verb used for the revealing of the covenant (<em>galah</em>) throughout the OT. Daniel blesses (<em>berakhi</em>, H1289) the God of heaven immediately — praise precedes petition.</p>',
    "20": '<p>Daniel\'s doxology begins: <em>leheve shemeh di-Elaha mevarekh</em> ("blessed be the name of God") — <em>shemeh</em> (H8036, name) + <em>mevarekh</em> (H1289, blessed). <em>Chokmah</em> (H2452, wisdom) and <em>geburah</em> (H1370, power/strength) belong to God from eternity (<em>min-alam ve-ad alam</em>, H5957, from ages to ages). The doxological form mirrors 1 Chr 29:11-12 (David\'s prayer) and anticipates Rev 5:12 ("worthy is the Lamb to receive power and wisdom").</p>',
    "21": '<p><strong>He changes times and seasons</strong> (<em>idanaya u-zimnaya</em>) — <em>idan</em> (H5732) and <em>zeman</em> (H2166) both mean appointed time/season; the pairing is emphatic. God removes and establishes kings (<em>melkin</em>, H4430): the political vision of Daniel grounds royal power entirely in divine appointment — Nebuchadnezzar\'s kingdom is gift and loan, not achievement. <strong>Gives wisdom to the wise</strong> — the paradox of grace: wisdom is given to those already counted wise, deepening what they have received.</p>',
    "22": '<p><strong>Reveals deep and hidden things</strong> (<em>gali atikin u-mesattarin</em>) — <em>atiq</em> (H6260, deep/ancient) and <em>setir</em> (H5642, hidden/concealed). The contrast between divine knowing and darkness (<em>cheshokha</em>, H2816) and light (<em>nehora</em>, H5094) is cosmological. God dwells in light and knows what is in the darkness — anticipating later apocalyptic passages where the heavenly throne shines like fire (7:9).</p>',
    "23": '<p>Daniel addresses God as "the God of my fathers" (<em>Elah avahathi</em>) — the covenant formula, invoking patriarchal continuity. <em>Hoda</em> (H3029, I give thanks/praise) + <em>meshabbach</em> (H7624, I praise). The shift from doxology (vv.20-22) to personal gratitude (v.23) marks the movement from cosmic to relational: the same God who sets kings over kingdoms has now answered Daniel\'s personal prayer.</p>',
    "24": '<p>Daniel does not rush to the king directly but first returns to Arioch to spare the wise men. <em>Al-te\'abed</em> (do not destroy, H7), the first word of the verse, is a plea for life — Daniel\'s concern for the other wise men even in his crisis moment reflects the moral character of covenant wisdom.</p>',
    "25": '<p><em>Behitvehal</em> (H927, with haste) — Arioch brings Daniel hurriedly. The framing of Daniel as the one "who can make known the interpretation" (<em>peshar</em>) sets up the theological claim: only one who stands in the divine council can bridge the gap the wise men declared unbridgeable (v.10-11).</p>',
    "26": '<p>The king\'s question: "are you able to make known to me the dream and its interpretation?" — <em>khayel</em> (H3546, are you able) echoes the wise men\'s "is there any man who <em>yikhel</em>?" (v.10). The answer will be: not Daniel, but Daniel\'s God.</p>',
    "27": '<p>Daniel\'s response begins with the explicit disclaimer: no wise man (<em>chakimin</em>, H2445), enchanter (<em>ashshaphim</em>, H826), magician (<em>chartumim</em>, H2749), or diviner (<em>gazerin</em>, H1505) can reveal this — the full fourfold list from v.2 is negated. The critique is systemic: Babylonian wisdom as an institution cannot access the divine council.</p>',
    "28": '<p><strong>There is a God in heaven who reveals mysteries</strong> — the thesis of the chapter and one of Daniel\'s central theological claims. <em>Elah bishmayya</em> (H426 + H8065, the God in heaven) — transcendent, unlike the gods who cannot dwell with flesh (v.11). <em>Raz</em> (mystery) + <em>moda</em> (H3046, he makes known) — God\'s response to human epistemic limitation is not silence but revelation. <strong>What will be in the latter days</strong> (<em>acharit yomayya</em>, H320 + H3118) — the eschatological formula; literally "the end of days," the technical phrase for the consummation of God\'s purposes.</p>',
    "29": '<p>The mysteries revealed correspond to the king\'s own nocturnal pondering (<em>ra\'yonayka</em>, H7476, thoughts/concerns on your bed). The dream is not random but responsive: God meets the king\'s genuine question about the future with a genuine answer, however unwelcome the answer may prove.</p>',
    "30": '<p><em>La di-chokmah di-itai vi ana min-kol-chayaya</em> — "not because of any wisdom that is in me more than all living." Daniel explicitly disclaims any personal superiority: the revelation is given for the king\'s sake (<em>di-peshar le-malka yehavon</em>) and for the sake of understanding (<em>ve-rayyoney libbak tinda</em>). Humility before revelation is a consistent posture throughout the book.</p>',
    "31": '<p><strong>Image</strong> (<em>tsalma</em>, H6755) — the Aramaic cognate of Hebrew <em>tselem</em> (image), the word used in Gen 1:26-27 for humanity as the image of God. The great image (H7690 <em>saggiy</em>, great/mighty) is the antithesis of the human image: where humanity bears the image of the living God, this image of human imperial glory will be shattered by the stone. The statue\'s <em>ziw</em> (H2122, brightness/brilliance) was terrifying — the language of divine theophany applied to human empire.</p>',
    "32": '<p>The metals descend in value but increase in hardness (gold → silver → bronze → iron), while the final material (iron mixed with clay, v.33) paradoxically combines hardness with brittleness. This inverse relationship — decreasing glory but increasing political hardness, ultimately terminating in a brittle mixture — is the interpretive key to the four-kingdom sequence.</p>',
    "33": '<p><em>Parzel</em> (H6523, iron) and <em>chaser</em> (H2635, clay) — the mixture of two incompatible materials. Iron does not bond with clay; the kingdom it represents will have apparent strength but structural fragility at every joint.</p>',
    "34": '<p><strong>Stone cut without hands</strong> (<em>eben di-gizrat la vi-yadayin</em>) — <em>eben</em> (H69) + <em>gizrat</em> (H1505, cut/carved) + <em>la vi-yadayin</em> (not by hands). The passive divine agency — the stone\'s origin is supernatural, not human political process. <em>Macha</em> (H4223, struck/smote) — the stone strikes the feet of the statue; the kingdom of God begins not at the top but at the foundational weakness of the structure.</p>',
    "35": '<p>The shattering produces material that becomes "like the chaff of the summer threshing floors" (<em>kemotz di-idaran qayt</em>) — the same image as Ps 1:4 and Isa 17:13 for what is blown away in judgment. The stone then fills the whole earth — a mountain (<em>tur</em>, H2906) encompassing everything, the inverse of the localized and decomposing statue. The imagery is total displacement, not coexistence.</p>',
    "36": '<p><em>Denah chelmah</em> (this is the dream) — the dream is declared as completed narration; now the <em>peshar</em> (interpretation) follows. The transition is formally marked, emphasizing that the revelation and its interpretation are two distinct gifts, both from God.</p>',
    "37": '<p><strong>King of kings</strong> (<em>malak malkin</em>) — an Akkadian/Aramaic royal title, used for Nebuchadnezzar by a Jewish exile deliberately: the king who thinks himself absolute sovereign is addressed with the imperial title, but immediately subordinated — "the God of heaven has given you the kingdom." <em>Malkhuta</em> (H4437, kingdom), <em>chaylah</em> (H2429, power), <em>taqpah</em> (H8632, strength), <em>yeqara</em> (H3367, honour) — the four attributes of the kingdom are given, not inherent.</p>',
    "38": '<p>Nebuchadnezzar is the golden head — the greatest of the four kingdoms. The dominion over "wherever the children of man dwell, the beasts of the field and the birds of the air" deliberately echoes Gen 1:28 (human dominion over creation), but here it is granted to a pagan king by the same God who granted dominion to Adam — the dominion mandate operating through an imperial vessel.</p>',
    "39": '<p>The second kingdom (<em>achori malkhuta</em>, a kingdom inferior to yours) and the third (bronze, ruling over all the earth) — the identifications of Medo-Persia and Greece are historically robust readings, though the text does not name them. The interpretive move from gold to silver to bronze enacts the deterioration: each kingdom receives less of the explicit divine endorsement given to Nebuchadnezzar.</p>',
    "40": '<p><strong>Fourth kingdom, strong as iron</strong> — <em>parzel di-mara kulla</em> (iron that breaks everything). The Roman Empire reading (traditional) fits the political history; the point is structural: the kingdom with the greatest apparent force also carries within it the fatal mixture. <em>Teqoph</em> (H8632, strength) appears again here — the iron\'s strength is real but the brittleness of v.41-43 qualifies it fundamentally.</p>',
    "41": '<p><strong>Feet partly of iron and partly of clay</strong> (<em>pesig di-parzel u-ve-chaser</em>) — <em>pesig</em> (H6536, divided) signals fracture built into the structure. The mixture of iron and clay is specifically described as "mixed human seed" (<em>zera enasha</em>, H2234 + H606) — possibly intermarriage between different peoples or fusion of incompatible elements within an empire. The strength is real but the binding is false.</p>',
    "42": '<p><em>Ve-etzbeata di-reglayyah</em> (the toes of the feet) — the toes are specified as partly strong, partly broken. The image builds: the statue is internally divided from its base, combining force and fragility in the same material and the same governance structure.</p>',
    "43": '<p>They will mingle (<em>mitharevin</em>, H6151) but will not hold together (<em>la yidbequn da-im da</em>) — <em>dbeq</em> (H1693) is the adhesion/cleave verb, the same word used for covenant bonding in Gen 2:24 (a man cleaves to his wife). What cannot cleave by covenant nature cannot hold.</p>',
    "44": '<p><strong>God of heaven will establish a kingdom</strong> — <em>yaqim Elah bishmayya malkhuta</em>. This kingdom has four negatives: it will never be destroyed (<em>la tithavad</em>), never surrendered to another people (<em>la tishtebiq le-am achoran</em>), it will crush (<em>tediqq</em>) and bring to an end all those kingdoms (<em>kol-illen malkhwata</em>), and it will endure forever (<em>hi tequm le-alam</em>). The divine kingdom is defined entirely by what it is not subject to — decay, transfer, defeat, termination.</p>',
    "45": '<p><strong>Stone cut from the mountain without hands</strong> — the interpretation confirms the image: the stone cut without human agency represents the kingdom the God of heaven establishes without human political process. <em>Uman</em> (H540, made sure/certain) — the same root as the Hebrew <em>amen</em>: the dream is certain (<em>aman</em>), the interpretation trustworthy. The epistemological confidence of prophecy rests in the character of the One who reveals.</p>',
    "46": '<p><strong>Nebuchadnezzar fell on his face</strong> (<em>nifal al-anpuhi</em>) — prostration before Daniel. <em>Segid</em> (H5457, to bow/worship) — the same Aramaic term that will be demanded of everyone before the gold image in ch 3, making Nebuchadnezzar\'s act here a pivot: the king who demands universal worship is himself on his face before a Jewish exile who represents the God who reveals. <em>Minchah</em> (H4504, offering) and <em>nichoach</em> (H5208, pleasing/fragrant) — sacrificial vocabulary applied to Daniel, a gesture that over-reads Daniel\'s role even if well-intentioned.</p>',
    "47": '<p><strong>Your God is God of gods and Lord of kings</strong> — <em>Elah elahin u-mare malkin</em>. The king\'s confession is formally correct: the God of Israel is supreme over other gods and over all earthly rulers. <strong>Revealer of mysteries</strong> (<em>galah razin</em>) — the compound title summarizes the entire chapter\'s theological argument. Nebuchadnezzar\'s confession is real but temporary (cf. ch 4); it is not yet the total submission of heart that the book awaits.</p>',
    "48": '<p><em>Nefaqu saggiye</em> (great gifts) and <em>shalit rav</em> (chief governor) — Daniel\'s elevation recapitulates the Joseph pattern (Gen 41:39-44). <em>Shiltan</em> (H7984, authority/dominion) over the province of Babylon and chief (<em>rav</em>, H7229) over all the wise men — the Jewish exile administers Babylonian wisdom, the reversal of the acculturation program of ch 1.</p>',
    "49": '<p>Daniel\'s intercession for his three companions — <em>u-Daniel ba\'ah min-qadam malka</em> (Daniel petitioned from before the king). The pattern of ch 1 repeats at the apex of ch 2: Daniel uses his position to secure the welfare of his covenant community. He is at court (<em>ve-Daniel bi-sha\'ar malka</em>, at the king\'s gate — the location of civic authority), exercising imperial power in service of covenant faithfulness.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'daniel')
    merge_comm(existing, DANIEL)
    save_comm('mkt-original', 'daniel', existing)
    print('Daniel 1-2 mkt-original commentary written.')

if __name__ == '__main__':
    main()
